class Solution(object):
    def firstMissingPositive(self, nums):
        """
        :type nums: List[int]
        :rtype: int
        """
        n = len(nums)
        contains_one = False

        # Check if 1 is present in the array
        for num in nums:
            if num == 1:
                contains_one = True
                break

        # If 1 is not present, it is the smallest missing positive integer
        if not contains_one:
            return 1

        # Replace negative numbers, zeros, and numbers larger than n with 1s
        for i in range(n):
            if nums[i] <= 0 or nums[i] > n:
                nums[i] = 1

        # Use index mapping to mark the presence of numbers
        for i in range(n):
            index = abs(nums[i]) - 1
            nums[index] = -abs(nums[index])

        # The first positive index + 1 is the missing number
        for i in range(n):
            if nums[i] > 0:
                return i + 1

        # If all numbers from 1 to n are present, the missing number is n + 1
        return n + 1

