class Solution(object):
    def maxNumber(self, nums1, nums2, k):
        """
        :type nums1: List[int]
        :type nums2: List[int]
        :type k: int
        :rtype: List[int]
        """
        def maxSequence(nums, k):
            stack = []
            discard = len(nums) - k
            for num in nums:
                while stack and stack[-1] < num and discard > 0:
                    stack.pop()
                    discard -= 1
                stack.append(num)
            return stack[:k]

        def merge(nums1, nums2):
            result = []
            while nums1 or nums2:
                if nums1 > nums2:
                    result.append(nums1.pop(0))
                else:
                    result.append(nums2.pop(0))
            return result

        max_num = []
        for i in range(k+1):
            if i <= len(nums1) and k-i <= len(nums2):
                max_num = max(max_num, merge(maxSequence(nums1, i), maxSequence(nums2, k-i)))
        return max_num

