    def containsNearbyAlmostDuplicate(self, nums, indexDiff, valueDiff):
        """
        :type nums: List[int]
        :type indexDiff: int
        :type valueDiff: int
        :rtype: bool
        """
        if valueDiff < 0:
            return False

        bucket = {}
        bucket_size = valueDiff + 1

        for i, num in enumerate(nums):
            bucket_id = num // bucket_size

            if bucket_id in bucket:
                return True

            if bucket_id - 1 in bucket and abs(num - bucket[bucket_id - 1]) < bucket_size:
                return True

            if bucket_id + 1 in bucket and abs(num - bucket[bucket_id + 1]) < bucket_size:
                return True

            bucket[bucket_id] = num

            if i >= indexDiff:
                del bucket[nums[i - indexDiff] // bucket_size]

        return False

