class Solution(object):
    def isSelfCrossing(self, distance):
        """
        :type distance: List[int]
        :rtype: bool
        """
        x, y = 0, 0
        dx, dy = 0, 1
        visited = set()
        visited.add((x, y))

        for d in distance:
            for _ in range(d):
                x += dx
                y += dy
                if (x, y) in visited:
                    return True
                visited.add((x, y))

            # Change direction counter-clockwise
            if dx == 0 and dy == 1:
                dx, dy = -1, 0
            elif dx == -1 and dy == 0:
                dx, dy = 0, -1
            elif dx == 0 and dy == -1:
                dx, dy = 1, 0
            elif dx == 1 and dy == 0:
                dx, dy = 0, 1

        return False

