class Solution(object):
    def removeInvalidParentheses(self, s):
        """
        :type s: str
        :rtype: List[str]
        """
        def is_valid(s):
            balance = 0
            for char in s:
                if char == '(':
                    balance += 1
                elif char == ')':
                    balance -= 1
                if balance < 0:
                    return False
            return balance == 0

        if not s:
            return [""]

        queue = deque([s])
        visited = set([s])
        result = []

        while queue:
            current = queue.popleft()
            if is_valid(current):
                result.append(current)
                continue

            for i in range(len(current)):
                if current[i] not in "()":
                    continue
                new_string = current[:i] + current[i+1:]
                if new_string not in visited:
                    visited.add(new_string)
                    queue.append(new_string)

        return result

