class Solution(object):
    def preimageSizeFZF(self, k):
        """
        :type k: int
        :rtype: int
        """
        def trailingZeroes(n):
            count = 0
            while n >= 5:
                n //= 5
                count += n
            return count

        def findFirst(n):
            low, high = 0, 5 * n
            while low < high:
                mid = (low + high) // 2
                if trailingZeroes(mid) < n:
                    low = mid + 1
                else:
                    high = mid
            return low

        def findLast(n):
            low, high = 0, 5 * n
            while low < high:
                mid = (low + high) // 2
                if trailingZeroes(mid) <= n:
                    low = mid + 1
                else:
                    high = mid
            return low - 1

        first = findFirst(k + 1)
        last = findLast(k)
        return last - first + 1

