class Solution(object):
    def containVirus(self, isInfected):
        """
        :type isInfected: List[List[int]]
        :rtype: int
        """
        m, n = len(isInfected), len(isInfected[0])
        directions = [(0, 1), (0, -1), (1, 0), (-1, 0)]
        walls = 0

        def spread(i, j, spread_set):
            if i < 0 or i >= m or j < 0 or j >= n or isInfected[i][j] == 2:
                return
            if isInfected[i][j] == 1:
                spread_set.add((i, j))
                for dx, dy in directions:
                    spread(i + dx, j + dy, spread_set)
            else:
                walls += 1
                isInfected[i][j] = 2

        def isolate(spread_set):
            for i, j in spread_set:
                isInfected[i][j] = 2

        def find_spread_sets():
            spread_sets = []
            for i in range(m):
                for j in range(n):
                    if isInfected[i][j] == 1:
                        spread_set = set()
                        spread(i, j, spread_set)
                        spread_sets.append(spread_set)
            return spread_sets

        def find_most_dangerous(spread_sets):
            max_danger = 0
            most_dangerous = None
            for spread_set in spread_sets:
                danger = 0
                for i, j in spread_set:
                    for dx, dy in directions:
                        x, y = i + dx, j + dy
                        if x < 0 or x >= m or y < 0 or y >= n or isInfected[x][y] == 2:
                            continue
                        if isInfected[x][y] == 0:
                            danger += 1
                if danger > max_danger:
                    max_danger = danger
                    most_dangerous = spread_set
            return most_dangerous

        while True:
            spread_sets = find_spread_sets()
            if not spread_sets:
                break
            most_dangerous = find_most_dangerous(spread_sets)
            walls += len(most_dangerous)
            isolate(most_dangerous)
            for spread_set in spread_sets:
                if spread_set != most_dangerous:
                    for i, j in spread_set:
                        spread(i, j, set())
        return walls

