                    elif s[i - 2] == '*':
                        dp[i] = (dp[i] + 15 * dp[i - 2]) % MOD  # '*' can be 11-26
            else:
                dp[i] = dp[i - 1] if s[i - 1] != '0' else 0  # Single digit decoding
                if i > 1:
                    if s[i - 2] == '1':
                        dp[i] = (dp[i] + dp[i - 2]) % MOD  # Two digits decoding starting with 1
